import React, { useState } from 'react'
import { useReviewsContext, ReviewsProvider } from './ReviewsProvider'
import './styles.css'
import { FaRegStar, FaStar } from "react-icons/fa6";

export function ReviewFormElement({ labeValue, formElement }) {
    return (<div className='form-element'>
        <label>{`${labeValue}:`}</label>
        {formElement}
    </div>)
}

export function ReviewRating({ rating }) {
    const [maxRating, setMaxRating] = useState(0)
    const [currRating, setCurrRating] = useState(0)
    const starsCount = [1, 2, 3, 4, 5]
    function handleStar(starValue) {
        setMaxRating((prev) => Math.max(prev, starValue))
        setCurrRating(starValue)
    }
    function getStar(starValue) {
        if (starValue <= currRating) {
            // return (<FaStar onClick={() => handleStar(starValue)} />)
            return (<FaStar onClick={() => handleStar(starValue)} />)

        }
        return (<FaRegStar onClick={() => handleStar(starValue)} />)
    }
    return (
        <div>{starsCount.map((star) => { getStar(star) }
        )}</div>
    )
}

export function ReviewForm() {
    const [formValues, setFormValues] = useState({
        reviewText: '',
        title: '',
        rating: 0
    })
    function handleTitle(e) {
        setFormValues((prev) => {
            return { ...prev, title: e.target.value }
        })
    }
    function handleReviewText(e) {
        setFormValues((prev) => {
            return { ...prev, reviewText: e.target.value }
        })
    }
    const TitleInput = () => <input type='text' placeholder='Title...' onChange={handleTitle} />
    const ReviewTextInput = () => <input type='text' placeholder='Please write your review...' onChange={handleReviewText} />
    return (
        <div className='form-container'>
            <ReviewFormElement labeValue={'Title'} formElement={<TitleInput />} />
            <ReviewFormElement labeValue={'Review'} formElement={<ReviewTextInput />} />
            <ReviewFormElement labeValue={'Rating'} formElement={<ReviewRating />} />
        </div>
    )
}

export function ReviewTitle({ title }) {
    return (
        <div>{title}</div>
    )
}

export function ReviewText({ reviewText }) {
    return (
        <div>{reviewText}</div>
    )
}

export function Reviews() {
    const { reviews } = useReviewsContext()
    if (reviews.length > 0) {
        return (
            <ul>
                {reviews.map(({ title, reviewText, rating }) => <li>
                    <ReviewTitle title={title} />
                    <ReviewText reviewText={reviewText} />
                    <ReviewRating rating={rating} />
                </li>)}
            </ul>
        )
    }
}
function ReviewsRating() {
    return <>
        <ReviewsProvider>
            <ReviewForm />
            <Reviews />
        </ReviewsProvider>
    </>
}

export default ReviewsRating
